# solution.py
"""Sport_Team_Coordinator / Team_Collaboration_Manager.

A self-contained, thread-safe, in-memory backend for coordinating a team:
users, projects, tasks, messaging (with attachments and threaded replies),
performance analytics (completion metrics + peer ratings), and exportable
reports (CSV / PDF).

The implementation is split into three logical layers that, per the task
brief, all live inside this single ``solution.py`` module:

    # models.py        -> enums, exceptions and data records
    # stores.py        -> lock-sharing in-memory stores / indexes
    # manager.py       -> TeamCollaborationManager (public API + reports)

Standard library only. All public read accessors return defensive copies so
callers can never mutate internal state by holding onto a returned object.
Every mutating/reading operation is guarded by a single shared re-entrant
lock, which makes the manager safe under concurrent access.
"""

# ---------------------------------------------------------------------------
# models.py
# ---------------------------------------------------------------------------
import csv
import io
import threading
from dataclasses import dataclass, field
from datetime import datetime
from enum import Enum
from typing import Callable, Dict, List, Optional, Set, Tuple


class UserRole(Enum):
    """Role-based access levels for collaborators."""

    MEMBER = "member"
    ADMIN = "admin"
    MANAGER = "manager"


class TaskStatus(Enum):
    """Lifecycle states for a task."""

    NOT_STARTED = "not_started"
    IN_PROGRESS = "in_progress"
    COMPLETED = "completed"


class ReportFormat(Enum):
    """Supported export formats."""

    CSV = "csv"
    PDF = "pdf"


class ReportType(Enum):
    """Kinds of analytics reports the manager can produce."""

    TEAM_PERFORMANCE = "team_performance"
    PROJECT_PROGRESS = "project_progress"
    INDIVIDUAL_PERFORMANCE = "individual_performance"


# --- Exception hierarchy ---------------------------------------------------
class TeamCollaborationError(Exception):
    """Base class for all domain errors raised by the manager."""


class ValidationError(TeamCollaborationError):
    """Raised when input fails validation."""


class NotFoundError(TeamCollaborationError):
    """Raised when a referenced entity does not exist."""


class AuthorizationError(TeamCollaborationError):
    """Raised when an actor is not permitted to perform an action."""


class DuplicateError(TeamCollaborationError):
    """Raised when a uniqueness constraint would be violated."""


class ConflictError(TeamCollaborationError):
    """Raised when an operation conflicts with current state."""


# --- Data records ----------------------------------------------------------
@dataclass
class Attachment:
    """A file attached to a message."""

    filename: str
    size: int
    uploaded_by: int
    uploaded_at: datetime

    def clone(self) -> "Attachment":
        return Attachment(self.filename, self.size, self.uploaded_by, self.uploaded_at)


@dataclass
class User:
    """A collaborator in the system."""

    id: int
    username: str
    email: str
    role: UserRole
    created_at: datetime

    def clone(self) -> "User":
        return User(self.id, self.username, self.email, self.role, self.created_at)


@dataclass
class Project:
    """A unit of work owned by a user and made up of tasks."""

    id: int
    name: str
    description: str
    start_date: datetime
    end_date: datetime
    owner_id: int

    def clone(self) -> "Project":
        return Project(
            self.id,
            self.name,
            self.description,
            self.start_date,
            self.end_date,
            self.owner_id,
        )


@dataclass
class Task:
    """A single piece of work that can be assigned and tracked."""

    id: int
    project_id: int
    title: str
    status: TaskStatus
    assignee_id: Optional[int]
    deadline: Optional[datetime]
    created_at: datetime
    started_at: Optional[datetime] = None
    completed_at: Optional[datetime] = None

    def clone(self) -> "Task":
        return Task(
            self.id,
            self.project_id,
            self.title,
            self.status,
            self.assignee_id,
            self.deadline,
            self.created_at,
            self.started_at,
            self.completed_at,
        )


@dataclass
class Message:
    """A message posted to a project or task, optionally a threaded reply."""

    id: int
    author_id: int
    body: str
    project_id: Optional[int]
    task_id: Optional[int]
    parent_id: Optional[int]
    created_at: datetime
    attachments: List[Attachment] = field(default_factory=list)
    edited_at: Optional[datetime] = None

    def clone(self) -> "Message":
        return Message(
            self.id,
            self.author_id,
            self.body,
            self.project_id,
            self.task_id,
            self.parent_id,
            self.created_at,
            [a.clone() for a in self.attachments],
            self.edited_at,
        )


@dataclass
class Rating:
    """A peer rating given to a user."""

    id: int
    rater_id: int
    ratee_id: int
    score: int
    feedback: str
    task_id: Optional[int]
    created_at: datetime

    def clone(self) -> "Rating":
        return Rating(
            self.id,
            self.rater_id,
            self.ratee_id,
            self.score,
            self.feedback,
            self.task_id,
            self.created_at,
        )


# ---------------------------------------------------------------------------
# stores.py
# ---------------------------------------------------------------------------
class _BaseStore:
    """A store that shares a single re-entrant lock with the manager.

    The shared lock guarantees that compound operations spanning several
    stores remain atomic and that all stores serialize on the same monitor.
    """

    def __init__(self, lock: threading.RLock) -> None:
        self._lock = lock


class _UserStore(_BaseStore):
    def __init__(self, lock: threading.RLock) -> None:
        super().__init__(lock)
        self.by_id: Dict[int, User] = {}
        self.username_index: Dict[str, int] = {}
        self.email_index: Dict[str, int] = {}


class _ProjectStore(_BaseStore):
    def __init__(self, lock: threading.RLock) -> None:
        super().__init__(lock)
        self.by_id: Dict[int, Project] = {}


class _TaskStore(_BaseStore):
    def __init__(self, lock: threading.RLock) -> None:
        super().__init__(lock)
        self.by_id: Dict[int, Task] = {}
        self.by_project: Dict[int, Set[int]] = {}
        self.by_assignee: Dict[int, Set[int]] = {}


class _MessageStore(_BaseStore):
    def __init__(self, lock: threading.RLock) -> None:
        super().__init__(lock)
        self.by_id: Dict[int, Message] = {}
        self.by_project: Dict[int, Set[int]] = {}
        self.by_task: Dict[int, Set[int]] = {}


class _PerformanceStore(_BaseStore):
    def __init__(self, lock: threading.RLock) -> None:
        super().__init__(lock)
        self.ratings: Dict[int, Rating] = {}
        self.by_ratee: Dict[int, Set[int]] = {}


class _ReportStore(_BaseStore):
    """Stateless aside from the shared lock; reports are computed on demand."""


# ---------------------------------------------------------------------------
# manager.py
# ---------------------------------------------------------------------------
class TeamCollaborationManager:
    """Coordinates users, projects, tasks, messaging, analytics and reports.

    Parameters
    ----------
    now:
        Optional zero-argument callable returning the current ``datetime``.
        Injecting a deterministic clock makes time-dependent behaviour
        testable. Defaults to :func:`datetime.datetime.now`.
    """

    def __init__(self, now: Optional[Callable[[], datetime]] = None) -> None:
        self._now: Callable[[], datetime] = now if now is not None else datetime.now
        self._lock = threading.RLock()
        self._id_counter = 0

        # All stores share the single manager lock (verified by tests).
        self.users = _UserStore(self._lock)
        self.projects = _ProjectStore(self._lock)
        self.tasks = _TaskStore(self._lock)
        self.messages = _MessageStore(self._lock)
        self.performance = _PerformanceStore(self._lock)
        self.reports = _ReportStore(self._lock)

    # -- internal helpers ---------------------------------------------------
    def now(self) -> datetime:
        return self._now()

    def _next_id(self) -> int:
        with self._lock:
            self._id_counter += 1
            return self._id_counter

    @staticmethod
    def _index_add(index: Dict[int, Set[int]], key: int, value: int) -> None:
        bucket = index.get(key)
        if bucket is None:
            bucket = set()
            index[key] = bucket
        bucket.add(value)

    @staticmethod
    def _index_remove(index: Dict[int, Set[int]], key: int, value: int) -> None:
        bucket = index.get(key)
        if bucket is not None:
            bucket.discard(value)
            if not bucket:
                del index[key]

    @staticmethod
    def _valid_email(email: str) -> bool:
        return isinstance(email, str) and bool(email.strip()) and "@" in email

    # ======================================================================
    # User management
    # ======================================================================
    def register_user(
        self, username: str, email: str, role: UserRole = UserRole.MEMBER
    ) -> User:
        with self._lock:
            if not isinstance(username, str) or not username.strip():
                raise ValidationError("username must be a non-empty string")
            if not self._valid_email(email):
                raise ValidationError("email must contain '@' and be non-empty")
            if not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole")

            uname = username.strip()
            mail = email.strip()
            if uname in self.users.username_index:
                raise DuplicateError("username already exists")
            if mail in self.users.email_index:
                raise DuplicateError("email already exists")

            uid = self._next_id()
            user = User(uid, uname, mail, role, self.now())
            self.users.by_id[uid] = user
            self.users.username_index[uname] = uid
            self.users.email_index[mail] = uid
            return user.clone()

    def get_user(self, user_id: int) -> User:
        with self._lock:
            user = self.users.by_id.get(user_id)
            if user is None:
                raise NotFoundError("user not found")
            return user.clone()

    def list_users(self) -> List[User]:
        with self._lock:
            return [self.users.by_id[uid].clone() for uid in sorted(self.users.by_id)]

    def update_user(
        self,
        user_id: int,
        username: Optional[str] = None,
        email: Optional[str] = None,
        role: Optional[UserRole] = None,
    ) -> User:
        with self._lock:
            user = self.users.by_id.get(user_id)
            if user is None:
                raise NotFoundError("user not found")

            new_username = user.username
            new_email = user.email
            new_role = user.role

            if username is not None:
                if not isinstance(username, str) or not username.strip():
                    raise ValidationError("username must be a non-empty string")
                candidate = username.strip()
                owner = self.users.username_index.get(candidate)
                if owner is not None and owner != user_id:
                    raise DuplicateError("username already exists")
                new_username = candidate

            if email is not None:
                if not self._valid_email(email):
                    raise ValidationError("email must contain '@' and be non-empty")
                candidate = email.strip()
                owner = self.users.email_index.get(candidate)
                if owner is not None and owner != user_id:
                    raise DuplicateError("email already exists")
                new_email = candidate

            if role is not None:
                if not isinstance(role, UserRole):
                    raise ValidationError("role must be a UserRole")
                new_role = role

            if new_username != user.username:
                del self.users.username_index[user.username]
                self.users.username_index[new_username] = user_id
                user.username = new_username
            if new_email != user.email:
                del self.users.email_index[user.email]
                self.users.email_index[new_email] = user_id
                user.email = new_email
            user.role = new_role
            return user.clone()

    def delete_user(self, user_id: int) -> None:
        with self._lock:
            user = self.users.by_id.get(user_id)
            if user is None:
                raise NotFoundError("user not found")

            for project in self.projects.by_id.values():
                if project.owner_id == user_id:
                    raise ConflictError("user owns one or more projects")

            for tid in self.tasks.by_assignee.get(user_id, set()):
                task = self.tasks.by_id.get(tid)
                if task is not None and task.status != TaskStatus.COMPLETED:
                    raise ConflictError("user has open assigned tasks")

            # Detach any remaining (completed) tasks from the assignee index.
            for tid in list(self.tasks.by_assignee.get(user_id, set())):
                task = self.tasks.by_id.get(tid)
                if task is not None:
                    task.assignee_id = None
            self.tasks.by_assignee.pop(user_id, None)

            del self.users.by_id[user_id]
            self.users.username_index.pop(user.username, None)
            self.users.email_index.pop(user.email, None)

    # ======================================================================
    # Project management
    # ======================================================================
    def create_project(
        self,
        name: str,
        start_date: datetime,
        end_date: datetime,
        owner_id: int,
        description: str = "",
    ) -> Project:
        with self._lock:
            if not isinstance(name, str) or not name.strip():
                raise ValidationError("project name must be a non-empty string")
            if end_date < start_date:
                raise ValidationError("end_date must not be before start_date")
            if owner_id not in self.users.by_id:
                raise NotFoundError("owner not found")

            pid = self._next_id()
            project = Project(
                pid, name.strip(), description or "", start_date, end_date, owner_id
            )
            self.projects.by_id[pid] = project
            return project.clone()

    def get_project(self, project_id: int) -> Project:
        with self._lock:
            project = self.projects.by_id.get(project_id)
            if project is None:
                raise NotFoundError("project not found")
            return project.clone()

    def list_projects(self) -> List[Project]:
        with self._lock:
            return [
                self.projects.by_id[pid].clone() for pid in sorted(self.projects.by_id)
            ]

    def update_project(
        self,
        project_id: int,
        name: Optional[str] = None,
        description: Optional[str] = None,
        start_date: Optional[datetime] = None,
        end_date: Optional[datetime] = None,
    ) -> Project:
        with self._lock:
            project = self.projects.by_id.get(project_id)
            if project is None:
                raise NotFoundError("project not found")

            new_name = project.name
            new_desc = project.description
            new_start = project.start_date
            new_end = project.end_date

            if name is not None:
                if not isinstance(name, str) or not name.strip():
                    raise ValidationError("project name must be a non-empty string")
                new_name = name.strip()
            if description is not None:
                new_desc = description
            if start_date is not None:
                new_start = start_date
            if end_date is not None:
                new_end = end_date
            if new_end < new_start:
                raise ValidationError("end_date must not be before start_date")

            project.name = new_name
            project.description = new_desc
            project.start_date = new_start
            project.end_date = new_end
            return project.clone()

    def delete_project(self, project_id: int) -> None:
        with self._lock:
            project = self.projects.by_id.get(project_id)
            if project is None:
                raise NotFoundError("project not found")

            for tid in list(self.tasks.by_project.get(project_id, set())):
                self._remove_task(tid)
            for mid in list(self.messages.by_project.get(project_id, set())):
                self._remove_message(mid)
            del self.projects.by_id[project_id]

    # ======================================================================
    # Task management
    # ======================================================================
    def create_task(
        self,
        project_id: int,
        title: str,
        assignee_id: Optional[int] = None,
        deadline: Optional[datetime] = None,
    ) -> Task:
        with self._lock:
            project = self.projects.by_id.get(project_id)
            if project is None:
                raise NotFoundError("project not found")
            if not isinstance(title, str) or not title.strip():
                raise ValidationError("task title must be a non-empty string")
            if assignee_id is not None and assignee_id not in self.users.by_id:
                raise NotFoundError("assignee not found")
            if deadline is not None and deadline < project.start_date:
                raise ValidationError("deadline must not be before project start")

            tid = self._next_id()
            task = Task(
                tid,
                project_id,
                title.strip(),
                TaskStatus.NOT_STARTED,
                assignee_id,
                deadline,
                self.now(),
            )
            self.tasks.by_id[tid] = task
            self._index_add(self.tasks.by_project, project_id, tid)
            if assignee_id is not None:
                self._index_add(self.tasks.by_assignee, assignee_id, tid)
            return task.clone()

    def get_task(self, task_id: int) -> Task:
        with self._lock:
            task = self.tasks.by_id.get(task_id)
            if task is None:
                raise NotFoundError("task not found")
            return task.clone()

    def list_tasks_by_project(self, project_id: int) -> List[Task]:
        with self._lock:
            if project_id not in self.projects.by_id:
                raise NotFoundError("project not found")
            ids = sorted(self.tasks.by_project.get(project_id, set()))
            return [self.tasks.by_id[i].clone() for i in ids]

    def list_tasks_by_assignee(self, assignee_id: int) -> List[Task]:
        with self._lock:
            if assignee_id not in self.users.by_id:
                raise NotFoundError("user not found")
            ids = sorted(self.tasks.by_assignee.get(assignee_id, set()))
            return [self.tasks.by_id[i].clone() for i in ids]

    def assign_task(self, task_id: int, assignee_id: int) -> Task:
        with self._lock:
            task = self.tasks.by_id.get(task_id)
            if task is None:
                raise NotFoundError("task not found")
            if assignee_id not in self.users.by_id:
                raise NotFoundError("assignee not found")

            if task.assignee_id is not None:
                self._index_remove(self.tasks.by_assignee, task.assignee_id, task_id)
            task.assignee_id = assignee_id
            self._index_add(self.tasks.by_assignee, assignee_id, task_id)
            return task.clone()

    def reassign_task(self, task_id: int, assignee_id: int) -> Task:
        # Reassignment shares assignment semantics (moves the index entry).
        return self.assign_task(task_id, assignee_id)

    def unassign_task(self, task_id: int) -> Task:
        with self._lock:
            task = self.tasks.by_id.get(task_id)
            if task is None:
                raise NotFoundError("task not found")
            if task.assignee_id is not None:
                self._index_remove(self.tasks.by_assignee, task.assignee_id, task_id)
                task.assignee_id = None
            return task.clone()

    def set_deadline(self, task_id: int, deadline: Optional[datetime]) -> Task:
        with self._lock:
            task = self.tasks.by_id.get(task_id)
            if task is None:
                raise NotFoundError("task not found")
            if deadline is not None:
                project = self.projects.by_id.get(task.project_id)
                if project is not None and deadline < project.start_date:
                    raise ValidationError("deadline must not be before project start")
            task.deadline = deadline
            return task.clone()

    def update_status(self, task_id: int, status: TaskStatus) -> Task:
        with self._lock:
            task = self.tasks.by_id.get(task_id)
            if task is None:
                raise NotFoundError("task not found")
            if not isinstance(status, TaskStatus):
                raise ValidationError("status must be a TaskStatus")

            moment = self.now()
            if status == TaskStatus.NOT_STARTED:
                task.started_at = None
                task.completed_at = None
            elif status == TaskStatus.IN_PROGRESS:
                if task.started_at is None:
                    task.started_at = moment
                task.completed_at = None
            elif status == TaskStatus.COMPLETED:
                if task.started_at is None:
                    task.started_at = moment
                task.completed_at = moment
            task.status = status
            return task.clone()

    def _remove_task(self, task_id: int) -> None:
        task = self.tasks.by_id.get(task_id)
        if task is None:
            return
        for mid in list(self.messages.by_task.get(task_id, set())):
            self._remove_message(mid)
        self._index_remove(self.tasks.by_project, task.project_id, task_id)
        if task.assignee_id is not None:
            self._index_remove(self.tasks.by_assignee, task.assignee_id, task_id)
        del self.tasks.by_id[task_id]

    # ======================================================================
    # Messaging
    # ======================================================================
    def post_message(
        self,
        author_id: int,
        body: str,
        project_id: Optional[int] = None,
        task_id: Optional[int] = None,
        parent_id: Optional[int] = None,
        attachments: Optional[List[Tuple[str, bytes]]] = None,
    ) -> Message:
        with self._lock:
            if (project_id is None) == (task_id is None):
                raise ValidationError(
                    "exactly one of project_id or task_id must be provided"
                )
            if author_id not in self.users.by_id:
                raise NotFoundError("author not found")
            if project_id is not None and project_id not in self.projects.by_id:
                raise NotFoundError("project not found")
            if task_id is not None and task_id not in self.tasks.by_id:
                raise NotFoundError("task not found")
            if parent_id is not None and parent_id not in self.messages.by_id:
                raise NotFoundError("parent message not found")

            body_str = body if isinstance(body, str) else ""
            pending = list(attachments) if attachments else []
            if not body_str.strip() and not pending:
                raise ValidationError("message must have a body or an attachment")

            moment = self.now()
            attachment_objs = [
                Attachment(filename, len(data), author_id, moment)
                for filename, data in pending
            ]

            mid = self._next_id()
            message = Message(
                mid,
                author_id,
                body_str,
                project_id,
                task_id,
                parent_id,
                moment,
                attachment_objs,
                None,
            )
            self.messages.by_id[mid] = message
            if project_id is not None:
                self._index_add(self.messages.by_project, project_id, mid)
            if task_id is not None:
                self._index_add(self.messages.by_task, task_id, mid)
            return message.clone()

    def edit_message(self, message_id: int, editor_id: int, new_body: str) -> Message:
        with self._lock:
            message = self.messages.by_id.get(message_id)
            if message is None:
                raise NotFoundError("message not found")
            if message.author_id != editor_id:
                raise AuthorizationError("only the author may edit a message")
            if not isinstance(new_body, str) or not new_body.strip():
                raise ValidationError("message body must be a non-empty string")
            message.body = new_body
            message.edited_at = self.now()
            return message.clone()

    def add_attachment(
        self, message_id: int, user_id: int, filename: str, data: bytes
    ) -> Message:
        with self._lock:
            message = self.messages.by_id.get(message_id)
            if message is None:
                raise NotFoundError("message not found")
            if message.author_id != user_id:
                raise AuthorizationError("only the author may add attachments")
            if not isinstance(filename, str) or not filename.strip():
                raise ValidationError("filename must be a non-empty string")
            message.attachments.append(
                Attachment(filename, len(data), user_id, self.now())
            )
            return message.clone()

    def list_messages_by_project(self, project_id: int) -> List[Message]:
        with self._lock:
            if project_id not in self.projects.by_id:
                raise NotFoundError("project not found")
            ids = sorted(self.messages.by_project.get(project_id, set()))
            return [self.messages.by_id[i].clone() for i in ids]

    def list_messages_by_task(self, task_id: int) -> List[Message]:
        with self._lock:
            if task_id not in self.tasks.by_id:
                raise NotFoundError("task not found")
            ids = sorted(self.messages.by_task.get(task_id, set()))
            return [self.messages.by_id[i].clone() for i in ids]

    def delete_message(self, message_id: int, user_id: int) -> None:
        with self._lock:
            message = self.messages.by_id.get(message_id)
            if message is None:
                raise NotFoundError("message not found")
            if message.author_id != user_id:
                raise AuthorizationError("only the author may delete a message")
            self._remove_message(message_id)

    def _remove_message(self, message_id: int) -> None:
        message = self.messages.by_id.get(message_id)
        if message is None:
            return
        if message.project_id is not None:
            self._index_remove(self.messages.by_project, message.project_id, message_id)
        if message.task_id is not None:
            self._index_remove(self.messages.by_task, message.task_id, message_id)
        del self.messages.by_id[message_id]

    # ======================================================================
    # Performance analytics
    # ======================================================================
    def get_completion_rate(self, user_id: int) -> float:
        with self._lock:
            if user_id not in self.users.by_id:
                raise NotFoundError("user not found")
            ids = self.tasks.by_assignee.get(user_id, set())
            if not ids:
                return 0.0
            completed = sum(
                1
                for i in ids
                if self.tasks.by_id[i].status == TaskStatus.COMPLETED
            )
            return completed / len(ids)

    def get_average_completion_time(self, user_id: int) -> Optional[float]:
        with self._lock:
            if user_id not in self.users.by_id:
                raise NotFoundError("user not found")
            durations = self._completion_durations(self.tasks.by_assignee.get(user_id, set()))
            if not durations:
                return None
            return sum(durations) / len(durations)

    def _completion_durations(self, task_ids) -> List[float]:
        durations: List[float] = []
        for tid in task_ids:
            task = self.tasks.by_id.get(tid)
            if (
                task is not None
                and task.status == TaskStatus.COMPLETED
                and task.started_at is not None
                and task.completed_at is not None
            ):
                durations.append((task.completed_at - task.started_at).total_seconds())
        return durations

    def submit_rating(
        self,
        rater_id: int,
        ratee_id: int,
        score: int,
        feedback: str = "",
        task_id: Optional[int] = None,
    ) -> Rating:
        with self._lock:
            if rater_id not in self.users.by_id:
                raise NotFoundError("rater not found")
            if ratee_id not in self.users.by_id:
                raise NotFoundError("ratee not found")
            if rater_id == ratee_id:
                raise ConflictError("a user cannot rate themselves")
            if isinstance(score, bool) or not isinstance(score, int):
                raise ValidationError("score must be an integer between 1 and 5")
            if score < 1 or score > 5:
                raise ValidationError("score must be between 1 and 5")
            if task_id is not None and task_id not in self.tasks.by_id:
                raise NotFoundError("task not found")

            rid = self._next_id()
            rating = Rating(
                rid, rater_id, ratee_id, score, feedback or "", task_id, self.now()
            )
            self.performance.ratings[rid] = rating
            self._index_add(self.performance.by_ratee, ratee_id, rid)
            return rating.clone()

    def get_ratings_summary(self, user_id: int) -> Dict[str, object]:
        with self._lock:
            if user_id not in self.users.by_id:
                raise NotFoundError("user not found")
            ids = sorted(self.performance.by_ratee.get(user_id, set()))
            ratings = [self.performance.ratings[i].clone() for i in ids]
            count = len(ratings)
            average = sum(r.score for r in ratings) / count if count else 0.0
            return {"count": count, "average": average, "ratings": ratings}

    def get_user_dashboard(self, user_id: int) -> Dict[str, object]:
        with self._lock:
            if user_id not in self.users.by_id:
                raise NotFoundError("user not found")
            ids = self.tasks.by_assignee.get(user_id, set())
            total = len(ids)
            completed = in_progress = not_started = 0
            for i in ids:
                status = self.tasks.by_id[i].status
                if status == TaskStatus.COMPLETED:
                    completed += 1
                elif status == TaskStatus.IN_PROGRESS:
                    in_progress += 1
                else:
                    not_started += 1

            durations = self._completion_durations(ids)
            avg_time = sum(durations) / len(durations) if durations else None
            summary = self.get_ratings_summary(user_id)
            return {
                "user_id": user_id,
                "total_tasks": total,
                "completed_tasks": completed,
                "in_progress_tasks": in_progress,
                "not_started_tasks": not_started,
                "completion_rate": completed / total if total else 0.0,
                "average_completion_time": avg_time,
                "rating_count": summary["count"],
                "rating_average": summary["average"],
            }

    # ======================================================================
    # Reports
    # ======================================================================
    def project_progress_report(self, project_id: int) -> Dict[str, object]:
        with self._lock:
            project = self.projects.by_id.get(project_id)
            if project is None:
                raise NotFoundError("project not found")

            ids = sorted(self.tasks.by_project.get(project_id, set()))
            total = len(ids)
            status_counts = {status.value: 0 for status in TaskStatus}
            per_assignee: Dict[int, Dict[str, object]] = {}
            overdue = completed = 0
            moment = self.now()

            for i in ids:
                task = self.tasks.by_id[i]
                status_counts[task.status.value] += 1
                if task.status == TaskStatus.COMPLETED:
                    completed += 1
                if (
                    task.deadline is not None
                    and task.deadline < moment
                    and task.status != TaskStatus.COMPLETED
                ):
                    overdue += 1
                if task.assignee_id is not None:
                    bucket = per_assignee.setdefault(
                        task.assignee_id, {"total": 0, "completed": 0}
                    )
                    bucket["total"] += 1
                    if task.status == TaskStatus.COMPLETED:
                        bucket["completed"] += 1

            return {
                "report_type": ReportType.PROJECT_PROGRESS.value,
                "project_id": project_id,
                "project_name": project.name,
                "total_tasks": total,
                "status_counts": status_counts,
                "completion_rate": completed / total if total else 0.0,
                "overdue_tasks": overdue,
                "per_assignee": per_assignee,
            }

    def team_performance_report(
        self, project_id: Optional[int] = None
    ) -> Dict[str, object]:
        with self._lock:
            if project_id is not None and project_id not in self.projects.by_id:
                raise NotFoundError("project not found")

            if project_id is not None:
                user_ids: Set[int] = set()
                for tid in self.tasks.by_project.get(project_id, set()):
                    assignee = self.tasks.by_id[tid].assignee_id
                    if assignee is not None:
                        user_ids.add(assignee)
            else:
                user_ids = {
                    uid for uid, bucket in self.tasks.by_assignee.items() if bucket
                }

            rows = [self._user_perf_row(uid, project_id) for uid in sorted(user_ids)]
            return {
                "report_type": ReportType.TEAM_PERFORMANCE.value,
                "project_id": project_id,
                "rows": rows,
            }

    def individual_performance_report(self, user_id: int) -> Dict[str, object]:
        with self._lock:
            if user_id not in self.users.by_id:
                raise NotFoundError("user not found")

            ids = sorted(self.tasks.by_assignee.get(user_id, set()))
            tasks_summary: List[Dict[str, object]] = []
            completed = 0
            for i in ids:
                task = self.tasks.by_id[i]
                if task.status == TaskStatus.COMPLETED:
                    completed += 1
                tasks_summary.append(
                    {
                        "task_id": task.id,
                        "title": task.title,
                        "status": task.status.value,
                        "project_id": task.project_id,
                        "deadline": task.deadline,
                        "started_at": task.started_at,
                        "completed_at": task.completed_at,
                    }
                )

            total = len(ids)
            durations = self._completion_durations(ids)
            avg_time = sum(durations) / len(durations) if durations else None
            summary = self.get_ratings_summary(user_id)
            return {
                "report_type": ReportType.INDIVIDUAL_PERFORMANCE.value,
                "user_id": user_id,
                "username": self.users.by_id[user_id].username,
                "total_tasks": total,
                "completed_tasks": completed,
                "completion_rate": completed / total if total else 0.0,
                "average_completion_time": avg_time,
                "rating_count": summary["count"],
                "rating_average": summary["average"],
                "tasks": tasks_summary,
            }

    def _user_perf_row(
        self, user_id: int, project_id: Optional[int] = None
    ) -> Dict[str, object]:
        assigned = self.tasks.by_assignee.get(user_id, set())
        if project_id is not None:
            task_ids = [
                tid for tid in assigned if self.tasks.by_id[tid].project_id == project_id
            ]
        else:
            task_ids = list(assigned)

        total = len(task_ids)
        completed = sum(
            1
            for tid in task_ids
            if self.tasks.by_id[tid].status == TaskStatus.COMPLETED
        )
        durations = self._completion_durations(task_ids)
        avg_time = sum(durations) / len(durations) if durations else None
        summary = self.get_ratings_summary(user_id)
        return {
            "user_id": user_id,
            "username": self.users.by_id[user_id].username,
            "total_tasks": total,
            "completed_tasks": completed,
            "completion_rate": completed / total if total else 0.0,
            "average_completion_time": avg_time,
            "rating_count": summary["count"],
            "rating_average": summary["average"],
        }

    # -- Export -------------------------------------------------------------
    def export_report(self, report: Dict[str, object], fmt: ReportFormat):
        if not isinstance(report, dict):
            raise ValidationError("report must be a dictionary")
        if not isinstance(fmt, ReportFormat):
            raise ValidationError("fmt must be a ReportFormat")
        if fmt == ReportFormat.CSV:
            return self._render_csv(report)
        return self._render_pdf(report)

    def _render_csv(self, report: Dict[str, object]) -> str:
        report_type = report.get("report_type")
        buffer = io.StringIO()
        writer = csv.writer(buffer)

        if report_type == ReportType.TEAM_PERFORMANCE.value:
            header = [
                "user_id",
                "username",
                "total_tasks",
                "completed_tasks",
                "completion_rate",
                "average_completion_time",
                "rating_count",
                "rating_average",
            ]
            writer.writerow(header)
            for row in report.get("rows", []):
                writer.writerow([_csv_cell(row.get(col)) for col in header])

        elif report_type == ReportType.PROJECT_PROGRESS.value:
            writer.writerow(["metric", "value"])
            writer.writerow(["project_id", _csv_cell(report.get("project_id"))])
            writer.writerow(["project_name", _csv_cell(report.get("project_name"))])
            writer.writerow(["total_tasks", _csv_cell(report.get("total_tasks", 0))])
            writer.writerow(
                ["completion_rate", _csv_cell(report.get("completion_rate", 0.0))]
            )
            writer.writerow(["overdue_tasks", _csv_cell(report.get("overdue_tasks", 0))])
            for status, count in report.get("status_counts", {}).items():
                writer.writerow(["status_" + str(status), _csv_cell(count)])
            for assignee_id, stats in report.get("per_assignee", {}).items():
                writer.writerow(
                    [
                        "assignee_" + str(assignee_id),
                        "{0}/{1}".format(
                            stats.get("completed", 0), stats.get("total", 0)
                        ),
                    ]
                )

        elif report_type == ReportType.INDIVIDUAL_PERFORMANCE.value:
            writer.writerow(
                [
                    "task_id",
                    "title",
                    "status",
                    "project_id",
                    "deadline",
                    "started_at",
                    "completed_at",
                ]
            )
            for task in report.get("tasks", []):
                writer.writerow(
                    [
                        _csv_cell(task.get("task_id")),
                        _csv_cell(task.get("title")),
                        _csv_cell(task.get("status")),
                        _csv_cell(task.get("project_id")),
                        _csv_cell(task.get("deadline")),
                        _csv_cell(task.get("started_at")),
                        _csv_cell(task.get("completed_at")),
                    ]
                )

        else:
            writer.writerow(["key", "value"])
            for key, value in report.items():
                writer.writerow([_csv_cell(key), _csv_cell(value)])

        return buffer.getvalue()

    def _render_pdf(self, report: Dict[str, object]) -> bytes:
        lines = self._report_text_lines(report)
        return _build_pdf(lines)

    @staticmethod
    def _report_text_lines(report: Dict[str, object]) -> List[str]:
        report_type = report.get("report_type", "report")
        lines = ["Report: {0}".format(report_type)]
        for key, value in report.items():
            if key == "report_type":
                continue
            if isinstance(value, (list, dict)):
                lines.append("{0}: {1} item(s)".format(key, len(value)))
            else:
                lines.append("{0}: {1}".format(key, value))
        return lines


