# Export helpers
# ---------------------------------------------------------------------------
def _csv_cell(value: object) -> str:
    if value is None:
        return ""
    return str(value)


def _build_pdf(lines: List[str]) -> bytes:
    """Build a minimal but structurally valid single-page PDF document."""

    def _escape(text: str) -> str:
        return (
            text.replace("\\", "\\\\").replace("(", "\\(").replace(")", "\\)")
        )

    safe_lines = [_escape("".join(ch for ch in line if 32 <= ord(ch) < 127)) for line in lines]
    if not safe_lines:
        safe_lines = [""]

    content_parts = ["BT", "/F1 12 Tf", "72 720 Td", "14 TL"]
    for index, line in enumerate(safe_lines):
        if index == 0:
            content_parts.append("({0}) Tj".format(line))
        else:
            content_parts.append("T* ({0}) Tj".format(line))
    content_parts.append("ET")
    content_stream = "\n".join(content_parts).encode("ascii")

    objects: List[bytes] = []
    objects.append(b"<< /Type /Catalog /Pages 2 0 R >>")
    objects.append(b"<< /Type /Pages /Kids [3 0 R] /Count 1 >>")
    objects.append(
        b"<< /Type /Page /Parent 2 0 R /MediaBox [0 0 612 792] "
        b"/Resources << /Font << /F1 5 0 R >> >> /Contents 4 0 R >>"
    )
    objects.append(
        b"<< /Length "
        + str(len(content_stream)).encode("ascii")
        + b" >>\nstream\n"
        + content_stream
        + b"\nendstream"
    )
    objects.append(
        b"<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>"
    )

    pdf = bytearray(b"%PDF-1.4\n")
    offsets: List[int] = []
    for number, body in enumerate(objects, start=1):
        offsets.append(len(pdf))
        pdf += "{0} 0 obj\n".format(number).encode("ascii")
        pdf += body
        pdf += b"\nendobj\n"

    xref_position = len(pdf)
    count = len(objects) + 1
    pdf += "xref\n0 {0}\n".format(count).encode("ascii")
    pdf += b"0000000000 65535 f \n"
    for offset in offsets:
        pdf += "{0:010d} 00000 n \n".format(offset).encode("ascii")
    pdf += "trailer\n<< /Size {0} /Root 1 0 R >>\n".format(count).encode("ascii")
    pdf += b"startxref\n"
    pdf += str(xref_position).encode("ascii")
    pdf += b"\n%%EOF\n"
    return bytes(pdf)


